import{_ as e,o as s,c as i,ae as t}from"./chunks/framework.C7FLYIpo.js";const g=JSON.parse('{"title":"설정","description":"OpenClaw의 고급 설정 및 개발 워크플로우","frontmatter":{"title":"설정","description":"OpenClaw의 고급 설정 및 개발 워크플로우"},"headers":[],"relativePath":"start/setup.md","filePath":"start/setup.md","lastUpdated":null}'),l={name:"start/setup.md"};function n(o,a,c,p,h,d){return s(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="설정" tabindex="-1">설정 <a class="header-anchor" href="#설정" aria-label="Permalink to &quot;설정&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>처음으로 설정하는 경우, <a href="/openclaw-docs-ko/start/getting-started">시작하기</a>부터 시작하십시오. 온보딩 세부 사항은 <a href="/openclaw-docs-ko/start/wizard">온보딩 (CLI)</a>를 참조하십시오.</p></div><h2 id="요약" tabindex="-1">요약 <a class="header-anchor" href="#요약" aria-label="Permalink to &quot;요약&quot;">​</a></h2><ul><li><strong>맞춤 설정은 저장소 외부에 있습니다:</strong> <code>~/.openclaw/workspace</code> (워크스페이스) + <code>~/.openclaw/openclaw.json</code> (구성).</li><li><strong>안정적인 워크플로우:</strong> macOS 앱을 설치하고 번들된 Gateway를 실행합니다.</li><li><strong>최신 워크플로우:</strong> <code>pnpm gateway:watch</code>를 통해 Gateway를 직접 실행하고 macOS 앱을 로컬 모드로 연결합니다.</li></ul><h2 id="사전-조건-소스에서" tabindex="-1">사전 조건 (소스에서) <a class="header-anchor" href="#사전-조건-소스에서" aria-label="Permalink to &quot;사전 조건 (소스에서)&quot;">​</a></h2><ul><li>Node 24 권장 (Node 22 LTS, 현재 <code>22.14+</code>, 여전히 지원됨)</li><li><code>pnpm</code> 권장 (<a href="/openclaw-docs-ko/install/bun">Bun 워크플로우</a>를 의도적으로 사용하는 경우 Bun)</li><li>Docker (선택 사항; 컨테이너화된 설정/e2e에만 필요 — <a href="/openclaw-docs-ko/install/docker">Docker</a> 참조)</li></ul><h2 id="맞춤-설정-전략-업데이트가-손상되지-않도록" tabindex="-1">맞춤 설정 전략 (업데이트가 손상되지 않도록) <a class="header-anchor" href="#맞춤-설정-전략-업데이트가-손상되지-않도록" aria-label="Permalink to &quot;맞춤 설정 전략 (업데이트가 손상되지 않도록)&quot;">​</a></h2><p>&quot;100% 내 취향에 맞는&quot; <em>그리고</em> 쉬운 업데이트를 원한다면, 맞춤 설정을 다음에 유지하십시오:</p><ul><li><strong>구성:</strong> <code>~/.openclaw/openclaw.json</code> (JSON/JSON5-ish)</li><li><strong>워크스페이스:</strong> <code>~/.openclaw/workspace</code> (스킬, 프롬프트, 메모리; 비공개 git 저장소로 만드십시오)</li></ul><p>한 번 부트스트랩:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span></span></code></pre></div><p>이 저장소 내에서 로컬 CLI 엔트리를 사용하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span></span></code></pre></div><p>아직 전역 설치가 없는 경우 <code>pnpm openclaw setup</code>으로 실행하십시오 (Bun 워크플로우를 사용하는 경우 <code>bun run openclaw setup</code>).</p><h2 id="이-저장소에서-gateway-실행" tabindex="-1">이 저장소에서 Gateway 실행 <a class="header-anchor" href="#이-저장소에서-gateway-실행" aria-label="Permalink to &quot;이 저장소에서 Gateway 실행&quot;">​</a></h2><p><code>pnpm build</code> 후 패키지된 CLI를 직접 실행할 수 있습니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openclaw.mjs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 18789</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbose</span></span></code></pre></div><h2 id="안정적인-워크플로우-macos-앱-우선" tabindex="-1">안정적인 워크플로우 (macOS 앱 우선) <a class="header-anchor" href="#안정적인-워크플로우-macos-앱-우선" aria-label="Permalink to &quot;안정적인 워크플로우 (macOS 앱 우선)&quot;">​</a></h2><ol><li><strong>OpenClaw.app</strong> (메뉴 바)을 설치 + 실행합니다.</li><li>온보딩/권한 체크리스트를 완료합니다 (TCC 프롬프트).</li><li>Gateway가 <strong>로컬</strong>로 실행 중인지 확인합니다 (앱이 관리합니다).</li><li>표면 연결 (예: WhatsApp):</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> channels</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span></span></code></pre></div><ol start="5"><li>정상 확인:</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> health</span></span></code></pre></div><p>빌드에서 온보딩을 사용할 수 없는 경우:</p><ul><li><code>openclaw setup</code>을 실행한 다음, <code>openclaw channels login</code>을 실행하고, Gateway를 수동으로 시작하십시오 (<code>openclaw gateway</code>).</li></ul><h2 id="최신-워크플로우-터미널의-gateway" tabindex="-1">최신 워크플로우 (터미널의 Gateway) <a class="header-anchor" href="#최신-워크플로우-터미널의-gateway" aria-label="Permalink to &quot;최신 워크플로우 (터미널의 Gateway)&quot;">​</a></h2><p>목표: TypeScript Gateway에서 작업하고, 핫 리로드를 사용하고, macOS 앱 UI를 연결 상태로 유지합니다.</p><h3 id="_0-선택-사항-소스에서도-macos-앱-실행" tabindex="-1">0) (선택 사항) 소스에서도 macOS 앱 실행 <a class="header-anchor" href="#_0-선택-사항-소스에서도-macos-앱-실행" aria-label="Permalink to &quot;0) (선택 사항) 소스에서도 macOS 앱 실행&quot;">​</a></h3><p>macOS 앱도 최신 버전으로 사용하려면:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./scripts/restart-mac.sh</span></span></code></pre></div><h3 id="_1-개발-gateway-시작" tabindex="-1">1) 개발 Gateway 시작 <a class="header-anchor" href="#_1-개발-gateway-시작" aria-label="Permalink to &quot;1) 개발 Gateway 시작&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway:watch</span></span></code></pre></div><p><code>gateway:watch</code>는 게이트웨이를 감시 모드로 실행하고 관련 소스, 구성 및 번들 플러그인 메타데이터 변경 시 재로드합니다.</p><p>Bun 워크플로우를 의도적으로 사용하는 경우 동등한 명령은:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway:watch</span></span></code></pre></div><h3 id="_2-macos-앱을-실행-중인-gateway에-연결" tabindex="-1">2) macOS 앱을 실행 중인 Gateway에 연결 <a class="header-anchor" href="#_2-macos-앱을-실행-중인-gateway에-연결" aria-label="Permalink to &quot;2) macOS 앱을 실행 중인 Gateway에 연결&quot;">​</a></h3><p><strong>OpenClaw.app</strong>에서:</p><ul><li>연결 모드: <strong>로컬</strong> 앱은 구성된 포트에서 실행 중인 게이트웨이에 연결합니다.</li></ul><h3 id="_3-확인" tabindex="-1">3) 확인 <a class="header-anchor" href="#_3-확인" aria-label="Permalink to &quot;3) 확인&quot;">​</a></h3><ul><li>앱 내 Gateway 상태는 <strong>&quot;기존 게이트웨이 사용 중...&quot;</strong> 으로 표시되어야 합니다</li><li>또는 CLI를 통해:</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> health</span></span></code></pre></div><h3 id="일반적인-함정" tabindex="-1">일반적인 함정 <a class="header-anchor" href="#일반적인-함정" aria-label="Permalink to &quot;일반적인 함정&quot;">​</a></h3><ul><li><strong>잘못된 포트:</strong> Gateway WS 기본값은 <code>ws://127.0.0.1:18789</code>입니다; 앱 + CLI를 동일한 포트로 유지하십시오.</li><li><strong>상태가 사는 곳:</strong><ul><li>채널/프로바이더 상태: <code>~/.openclaw/credentials/</code></li><li>모델 인증 프로파일: <code>~/.openclaw/agents/&lt;agentId&gt;/agent/auth-profiles.json</code></li><li>세션: <code>~/.openclaw/agents/&lt;agentId&gt;/sessions/</code></li><li>로그: <code>/tmp/openclaw/</code></li></ul></li></ul><h2 id="자격-증명-저장소-지도" tabindex="-1">자격 증명 저장소 지도 <a class="header-anchor" href="#자격-증명-저장소-지도" aria-label="Permalink to &quot;자격 증명 저장소 지도&quot;">​</a></h2><p>인증을 디버깅하거나 백업할 항목을 결정할 때 사용하십시오:</p><ul><li><strong>WhatsApp</strong>: <code>~/.openclaw/credentials/whatsapp/&lt;accountId&gt;/creds.json</code></li><li><strong>Telegram 봇 토큰</strong>: 구성/환경 변수 또는 <code>channels.telegram.tokenFile</code> (일반 파일만; 심볼릭 링크 거부됨)</li><li><strong>Discord 봇 토큰</strong>: 구성/환경 변수 또는 SecretRef (env/file/exec 프로바이더)</li><li><strong>Slack 토큰</strong>: 구성/환경 변수 (<code>channels.slack.*</code>)</li><li><strong>페어링 허용 목록</strong>: <ul><li><code>~/.openclaw/credentials/&lt;channel&gt;-allowFrom.json</code> (기본 계정)</li><li><code>~/.openclaw/credentials/&lt;channel&gt;-&lt;accountId&gt;-allowFrom.json</code> (비기본 계정)</li></ul></li><li><strong>모델 인증 프로파일</strong>: <code>~/.openclaw/agents/&lt;agentId&gt;/agent/auth-profiles.json</code></li><li><strong>파일 기반 비밀 페이로드 (선택 사항)</strong>: <code>~/.openclaw/secrets.json</code></li><li><strong>레거시 OAuth 가져오기</strong>: <code>~/.openclaw/credentials/oauth.json</code> 자세한 내용: <a href="/openclaw-docs-ko/gateway/security/#credential-storage-map">보안</a>.</li></ul><h2 id="설정-업데이트-설정을-망가뜨리지-않고" tabindex="-1">설정 업데이트 (설정을 망가뜨리지 않고) <a class="header-anchor" href="#설정-업데이트-설정을-망가뜨리지-않고" aria-label="Permalink to &quot;설정 업데이트 (설정을 망가뜨리지 않고)&quot;">​</a></h2><ul><li><code>~/.openclaw/workspace</code>와 <code>~/.openclaw/</code>를 &quot;내 항목&quot;으로 유지하십시오; 개인 프롬프트/구성을 <code>openclaw</code> 저장소에 넣지 마십시오.</li><li>소스 업데이트: <code>git pull</code> + 선택한 패키지 관리자 설치 단계 (기본값 <code>pnpm install</code>; Bun 워크플로우의 경우 <code>bun install</code>) + 일치하는 <code>gateway:watch</code> 명령을 계속 사용하십시오.</li></ul><h2 id="linux-systemd-사용자-서비스" tabindex="-1">Linux (systemd 사용자 서비스) <a class="header-anchor" href="#linux-systemd-사용자-서비스" aria-label="Permalink to &quot;Linux (systemd 사용자 서비스)&quot;">​</a></h2><p>Linux 설치는 systemd <strong>사용자</strong> 서비스를 사용합니다. 기본적으로 systemd는 로그아웃/유휴 시 사용자 서비스를 중지하여 Gateway를 종료합니다. 온보딩은 사용자를 위해 lingering을 활성화하려고 시도합니다 (sudo를 요청할 수 있습니다). 여전히 비활성화된 경우 실행하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> loginctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable-linger</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $USER</span></span></code></pre></div><p>항상 켜져 있거나 멀티 사용자 서버의 경우, 사용자 서비스 대신 <strong>시스템</strong> 서비스를 고려하십시오 (lingering 불필요). systemd 참고 사항은 <a href="/openclaw-docs-ko/gateway/">게이트웨이 런북</a>을 참조하십시오.</p><h2 id="관련-문서" tabindex="-1">관련 문서 <a class="header-anchor" href="#관련-문서" aria-label="Permalink to &quot;관련 문서&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/gateway/">게이트웨이 런북</a> (플래그, 감독, 포트)</li><li><a href="/openclaw-docs-ko/gateway/configuration">게이트웨이 구성</a> (구성 스키마 + 예시)</li><li><a href="/openclaw-docs-ko/channels/discord">Discord</a> 및 <a href="/openclaw-docs-ko/channels/telegram">Telegram</a> (응답 태그 + replyToMode 설정)</li><li><a href="/openclaw-docs-ko/start/openclaw">OpenClaw 어시스턴트 설정</a></li><li><a href="/openclaw-docs-ko/platforms/macos">macOS 앱</a> (게이트웨이 수명 주기)</li></ul>`,53)])])}const k=e(l,[["render",n]]);export{g as __pageData,k as default};
